template <typename T, int EPW, int FD, bool BS>
static inline void launch_by_ci(int ci, T seed, T* ptr, long size, size_t wg) {
#define DO_LAUNCH(CI) launch_ci_kernel<T, EPW, FD, BS, CI>(seed, ptr, size, wg)
  CI_SWITCH(DO_LAUNCH);
#undef DO_LAUNCH
}

template <typename F>
double benchmark3(F&& fn) {
  double sum = 0.0;
  for (int i = 0; i < 3; i++) sum += fn();
  return sum / 3.0;
}

template <typename T, int EPW, int FD, bool BS>
double time_kernel(int ci, T seed, T* ptr, long size, size_t wg) {
  return benchmark3([&]() {
    cudaEvent_t ev_start, ev_stop;
    CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
    CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
    CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
    launch_by_ci<T, EPW, FD, BS>(ci, seed, ptr, size, wg);
    CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
    CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
    float ms = 0.0f;
    CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
    CUDA_SAFE_CALL(cudaGetLastError());
    return (double)ms;
  });
}

extern "C" void mixbenchGPU(double* c, long size) {
  const bool block_strided = false;
  const bool host_allocated = false;
  const bool use_os_timer = false;
  const size_t workgroupsize = 256;
  const unsigned int elements_per_wi = 8;
  const unsigned int fusion_degree = 4;

  printf("Workgroup size:         %zu\n", workgroupsize);
  printf("Elements per workitem:  %u\n", elements_per_wi);
  printf("Workitem fusion degree: %u\n", fusion_degree);

  const char* benchtype = block_strided ? "Workgroup" : "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation = host_allocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n", use_os_timer ? "OS based" : "CL event based");

  cudaDeviceProp prop = GetDeviceProperties();
  bool enable_dp = (prop.major > 1) || (prop.major == 1 && prop.minor >= 3);
  if (!enable_dp) {
    printf("Warning:                Double precision computations are not supported\n");
  }
  bool enable_hp = IsFP16Supported();
  if (!enable_hp) {
    printf("Warning:                Half precision computations are not supported\n");
  }

  double* d_buffer = nullptr;
  CUDA_SAFE_CALL(cudaMalloc((void**)&d_buffer, (size_t)size * sizeof(double)));
  CUDA_SAFE_CALL(cudaMemset(d_buffer, 0, (size_t)size * sizeof(double)));

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  {
    const long reduced_grid_size = size / 256;
    short* p = reinterpret_cast<short*>(d_buffer);
    launch_ci_kernel<short, 1, 1, false, 0>((short)1, p, reduced_grid_size, workgroupsize);
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
  }

  printf("------------------------------------------------------------------------------------------------ CSV data -----------------------------------------------------------------------------------------------------\n");
  printf("Experiment ID, Single Precision ops,,,,              Double precision ops,,,,              Half precision ops,,,,                Integer operations,,, \n");
  printf("Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    const int current_compute_iterations = compute_iterations[i];
    const long compute_grid_size = size / elements_per_wi / fusion_degree;
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2LL * elements_per_wi * current_compute_iterations) * (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    double kernel_time_mad_sp = time_kernel<float, 8, 4, false>(
        current_compute_iterations, 1.0f, reinterpret_cast<float*>(d_buffer), size, workgroupsize);

    double kernel_time_mad_dp = 0.0;
    if (enable_dp) {
      kernel_time_mad_dp = time_kernel<double, 8, 4, false>(
          current_compute_iterations, 1.0, reinterpret_cast<double*>(d_buffer), size, workgroupsize);
    }

    double kernel_time_mad_hp = 0.0;
    if (enable_hp) {
      kernel_time_mad_hp = time_kernel<__half2, 8, 4, false>(
          current_compute_iterations, __float2half2_rn(1.0f), reinterpret_cast<__half2*>(d_buffer), size,
          workgroupsize);
    }

    double kernel_time_mad_int = time_kernel<int, 8, 4, false>(
        current_compute_iterations, 1, reinterpret_cast<int*>(d_buffer), size, workgroupsize);

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations) / kernel_time_mad_dp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)2 * computations) / ((double)memoryoperations * sizeof(__half2)),
        kernel_time_mad_hp,
        ((double)2 * computations) / kernel_time_mad_hp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int,
        ((double)computations) / kernel_time_mad_int * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
            (1000. * 1000. * 1000.));
  }

  printf("------------------------------------------------------------------------------------------------------------------------------------------------------------\n");

  CUDA_SAFE_CALL(cudaMemcpy(c, d_buffer, (size_t)size * sizeof(double), cudaMemcpyDeviceToHost));
  CUDA_SAFE_CALL(cudaFree(d_buffer));
}
